SELECT DISTINCT ?part ?partName ?partType ?typeName WHERE {
  <TMT/block/TMT::Project::Work%2520Packages::Telescope::WorkPackages::Control::Alignment%2520and%2520Phasing%2520System::Systems%2520Engineering::01%2520Components::Operational::APS::Conceptual%2520Design::APS%2520Conceptual> vocab:StructuredClassifier_part ?part .
  OPTIONAL { ?part vocab:NamedElement_name ?partName . }
